window.onload = function () {
    initializeCheckboxes();
};

function initializeCheckboxes() {
    const allCheckbox = document.getElementById("allchecked");
    if (!allCheckbox) return;
    const serviceCheckboxes = [
        "binrouteschecked", "councillorschecked", "secondaryschoolchecked",
        "recyclingchecked", "librarychecked", "nurseryschoolchecked",
        "primaryschoolchecked", "regofficechecked"
    ];

    // Set "All Services" to unchecked and uncheck/enable all individual checkboxes
    allCheckbox.checked = false;
    serviceCheckboxes.forEach(id => {
        const checkbox = document.getElementById(id);
        checkbox.checked = false;    
        checkbox.disabled = false;   
    });
}

function getCheckbox(chckbx) {
    const allCheckbox = document.getElementById("allchecked");
    const serviceCheckboxes = [
        "binrouteschecked", "councillorschecked", "secondaryschoolchecked",
        "recyclingchecked", "librarychecked", "nurseryschoolchecked",
        "primaryschoolchecked", "regofficechecked"
    ];

    if (chckbx.id === "allchecked") {
        if (allCheckbox.checked) {
            // When "All Services" is checked, tick and disable all individual checkboxes
            serviceCheckboxes.forEach(id => {
                const checkbox = document.getElementById(id);
                checkbox.checked = true;     // Tick each box
                checkbox.disabled = true;    // Disable to gray out
            });
        } else {
            // Enable and untick all individual checkboxes when "All Services" is unchecked
            serviceCheckboxes.forEach(id => {
                const checkbox = document.getElementById(id);
                checkbox.checked = false;    // Untick each box
                checkbox.disabled = false;   // Re-enable
            });
        }
    } else {
        // If any individual checkbox is checked, uncheck "All Services"
        if (chckbx.checked) {
            allCheckbox.checked = false;
        }
    }
}

